mapper.insert:
INSERT INTO woorido.expense_requests (
  id, meeting_id, created_by, title, amount,
  description, receipt_url, status, created_at
) VALUES (
  #{id}, #{meetingId}, #{createdBy}, #{title}, #{amount},
  #{description, jdbcType=VARCHAR}, #{receiptUrl, jdbcType=VARCHAR}, #{status}, #{createdAt}
)

mapper.update:
UPDATE woorido.expense_requests
SET status = #{status},
    approved_at = #{approvedAt, jdbcType=TIMESTAMP}
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM woorido.expense_requests er
JOIN woorido.meetings m ON m.id = er.meeting_id
WHERE m.challenge_id = #{challengeId}
  AND er.created_by = #{userId}
  AND er.status = 'APPROVED'
  AND er.approved_at IS NOT NULL
  AND er.approved_at >= #{since}
